{{-- Partial: Donor agreement form fields --}}
<div class="mb-3"><label class="form-label">Agreement Type <span class="badge bg-secondary ms-1">Required</span></label><select class="form-select" name="agreement_type"><option value="">Select type...</option><option value="donation">Donation</option><option value="loan">Loan</option><option value="deposit">Deposit</option></select></div>
<div class="row"><div class="col-md-6 mb-3"><label class="form-label">Start Date <span class="badge bg-secondary ms-1">Recommended</span></label><input type="date" class="form-control" name="start_date"></div><div class="col-md-6 mb-3"><label class="form-label">End Date <span class="badge bg-secondary ms-1">Optional</span></label><input type="date" class="form-control" name="end_date"></div></div>
<div class="mb-3"><label class="form-label">Terms <span class="badge bg-secondary ms-1">Recommended</span></label><textarea class="form-control" name="terms" rows="4"></textarea></div>
<div class="mb-3"><label class="form-label">Notes <span class="badge bg-secondary ms-1">Optional</span></label><textarea class="form-control" name="notes" rows="2"></textarea></div>
